import React, { useEffect, useRef } from 'react';

export interface RemoteParticipant {
  stream: MediaStream;
  userId: string;
  role: 'broadcaster' | 'viewer';
}

interface VideoGridProps {
  streams: Map<string, RemoteParticipant>;
  localStream?: MediaStream | null;
  localUserId?: string;
}

const VideoTile: React.FC<{
  stream: MediaStream;
  name: string;
  isBroadcaster: boolean;
  isLocal?: boolean;
}> = ({ stream, name, isBroadcaster, isLocal }) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if (videoRef.current && stream) {
      videoRef.current.srcObject = stream;
    }
  }, [stream]);

  return (
    <div style={styles.tile}>
      <video
        ref={videoRef}
        autoPlay
        playsInline
        muted={isLocal}
        style={styles.video}
      />
      <div style={styles.nameTag}>
        <span style={isBroadcaster ? styles.broadcasterName : styles.viewerName}>
          {name} {isLocal && '(You)'} {isBroadcaster && '★'}
        </span>
      </div>
    </div>
  );
};

export const VideoGrid: React.FC<VideoGridProps> = ({
  streams,
  localStream,
  localUserId,
}) => {
  const participantCount = streams.size + (localStream ? 1 : 0);

  // Calculate grid columns based on participant count
  const getGridColumns = () => {
    if (participantCount <= 1) return 1;
    if (participantCount <= 4) return 2;
    if (participantCount <= 9) return 3;
    return 4;
  };

  return (
    <div style={{ ...styles.grid, gridTemplateColumns: `repeat(${getGridColumns()}, 1fr)` }}>
      {/* Local video first */}
      {localStream && (
        <VideoTile
          stream={localStream}
          name={localUserId || 'You'}
          isBroadcaster={false}
          isLocal={true}
        />
      )}

      {/* Remote videos */}
      {Array.from(streams.entries()).map(([participantId, participant]) => (
        <VideoTile
          key={participantId}
          stream={participant.stream}
          name={participant.userId}
          isBroadcaster={participant.role === 'broadcaster'}
        />
      ))}

      {/* Empty state */}
      {participantCount === 0 && (
        <div style={styles.emptyState}>
          Waiting for participants...
        </div>
      )}
    </div>
  );
};

const styles: { [key: string]: React.CSSProperties } = {
  grid: {
    display: 'grid',
    gap: '10px',
    width: '100%',
    minHeight: '300px',
  },
  tile: {
    position: 'relative',
    backgroundColor: '#1a1a1a',
    borderRadius: '8px',
    overflow: 'hidden',
    aspectRatio: '16/9',
  },
  video: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
  },
  nameTag: {
    position: 'absolute',
    bottom: '8px',
    left: '8px',
    padding: '4px 8px',
    backgroundColor: 'rgba(0, 0, 0, 0.6)',
    borderRadius: '4px',
  },
  broadcasterName: {
    color: '#ffc107',
    fontSize: '12px',
    fontWeight: 'bold',
  },
  viewerName: {
    color: 'white',
    fontSize: '12px',
  },
  emptyState: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#2a2a2a',
    borderRadius: '8px',
    color: '#888',
    padding: '40px',
    gridColumn: '1 / -1',
  },
};
